window.KOANS_DATA = [{"n":1,"title":"О пустоте аргумента","slug":"001-o-pustote-argumenta","category":"javascript","tags":["arguments","undefined","functions"],"source":"Монастырь Мацуо-дэра, 1174 г.","segments":[{"k":"source","t":"Из свитков монастыря Мацуо-дэра, 1174 г. Комментарий к ECMA-262, глава о призвании функций."},{"k":"source","t":"Ученик пришёл к мастеру и написал на песке:"},{"k":"code","lang":"js","t":"function gate(a, b, c) {}\ngate(1)"},{"k":"student","t":"Ученик: «Мастер, я передал одно — но врата ждут троих. Будет ли ошибка?»"},{"k":"action","t":"Мастер ударил его палкой."},{"k":"master","t":"Мастер: «Ворота не закрываются от того, что гостей пришло меньше. Пустые места уже заняты — тишиной.»"},{"k":"student","t":"Ученик: «Значит b и c — это undefined?»"},{"k":"master","t":"Мастер: «Нет. Это mu. Они не определены — но они есть.»"},{"k":"haiku","t":"Ветер дует — три чаши на столе. Одна полна."},{"k":"question","t":"С чем ты уйдёшь: Если undefined — это отсутствие значения, то чем отличается аргумент, который не передали, от аргумента, которому явно передали undefined?"}]},{"n":2,"title":"О равенстве неравных","slug":"002-o-ravenstve-neravnykh","category":"javascript","tags":["equality","coercion","abstract-equality"],"source":"Храм Энряку-дзи, 1231 г.","segments":[{"k":"source","t":"Из обгоревшего пергамента храма Энряку-дзи, 1231 г. Приписывается монаху Рэндану, толкователю Абстрактных Операций."},{"k":"code","lang":"js","t":"[] == ![]   // true"},{"k":"student","t":"Ученик: «Мастер, пустой массив равен отрицанию пустого массива. Это... невозможно.»"},{"k":"master","t":"Мастер: «Ты спросил у языка \"равны ли они?\". Язык начал работу по Абстрактному Алгоритму Сравнения. Он не обязан думать о смысле.»"},{"k":"student","t":"Ученик: «Но [] — это объект. ![] — это false. Как они могут быть равны?»"},{"k":"master","t":"Мастер: «Потому что ты написал ==. Не ===. Ты попросил сравнения с принуждением. Язык принудил. Не жалуйся на результат принуждения, которое сам заказал.»"},{"k":"student","t":"Ученик: «Тогда === всегда лучше?»"},{"k":"action","t":"Мастер закрыл глаза."},{"k":"master","t":"Мастер: «Всегда — слово самонадеянных. Но да.»"},{"k":"haiku","t":"Пустая чаша. Отрицание пустой чаши. Оба — на столе."},{"k":"question","t":"С чем ты уйдёшь: Язык исполняет правила, не намерения. Когда ты пишешь ==, ты подписываешь договор с Абстрактным Алгоритмом. Ты читал его?"}]},{"n":3,"title":"О мёртвой зоне","slug":"003-o-mertvoi-zone","category":"javascript","tags":["hoisting","let","temporal-dead-zone","var"],"source":"Тодай-дзи, 1309 г.","segments":[{"k":"source","t":"Найден в подвалах Тодай-дзи, 1309 г. Монах Кэйсаку записал на обороте сутры «О Временном Связывании». Настоятель был в ярости."},{"k":"source","t":"Ученик уверенно написал:"},{"k":"code","lang":"js","t":"console.log(x)\nlet x = 5"},{"k":"student","t":"Ученик: «Мастер, с var это работало. Я получал undefined, но шёл дальше.»"},{"k":"master","t":"Мастер: «Ты шёл дальше с пустотой в руках и называл это путём.»"},{"k":"student","t":"Ученик: «А теперь — ReferenceError. Меня не пускают.»"},{"k":"master","t":"Мастер: «Нет. Тебя наконец остановили.»"},{"k":"student","t":"Ученик: «Но переменная же существует! Она объявлена ниже!»"},{"k":"action","t":"Мастер поднял чашку чая и держал её над полом."},{"k":"master","t":"Мастер: «Эта чашка — твоя. Я уже решил отдать. Но пока я не разжал пальцы — протяни руку и возьми.»"},{"k":"action","t":"Ученик протянул руку. Мастер ударил по ней палкой."},{"k":"master","t":"Мастер: «Temporal Dead Zone. Знание о том, что дар существует, не даёт права взять его до срока.»"},{"k":"haiku","t":"Зерно в земле — уже дерево. Но тянешь — рвутся корни."},{"k":"question","t":"С чем ты уйдёшь: var поднимал и значение, и имя — но давал undefined, тихую ложь. let поднимает имя, но запрещает касаться. Что милосерднее — ложь, которая не ломает, или правда, которая бьёт?"}]},{"n":4,"title":"О потерянном this","slug":"004-o-poteryannom-this","category":"javascript","tags":["this","bind","arrow-functions","context"],"source":"Горный монастырь Коя-сан, 1287 г.","segments":[{"k":"source","t":"Из дневников отшельника Фудзивара-но-Скоупу, 1287 г. Горный монастырь Коя-сан. Запись сделана кистью, вымоченной в слезах стажёра."},{"k":"code","lang":"js","t":"const monk = {\n  name: 'Кэйсаку',\n  speak() { return this.name }\n}\n\nconst fn = monk.speak\nfn()  // undefined"},{"k":"student","t":"Ученик: «Мастер! Монах знает своё имя. Но когда я вынул его речь из тела — он забыл, кто он.»"},{"k":"action","t":"Мастер молчал долго."},{"k":"master","t":"Мастер: «Вырви сердце из груди воина. Будет ли оно биться за его господина?»"},{"k":"student","t":"Ученик: «Нет...»"},{"k":"master","t":"Мастер: «this — не память. Это верность. Она существует только внутри служения. Метод, извлечённый из объекта, — ронин. Он служит window. Или никому.»"},{"k":"student","t":"Ученик: «Тогда .bind() — это клятва верности?»"},{"k":"action","t":"Мастер слегка кивнул."},{"k":"master","t":"Мастер: «А стрелочная функция — это монах, который никогда не покидал храм. У него нет своего this. Он навсегда привязан к месту, где был рождён.»"},{"k":"haiku","t":"Меч без руки. Кому он верен теперь? Лежит в траве."},{"k":"question","t":"С чем ты уйдёшь: Стрелочная функция не теряет this, потому что никогда им не владела. Можно ли потерять то, чего у тебя не было? И что свободнее — тот, кто привязан навечно, или тот, кто привязывается заново при каждом вызове?"}]},{"n":5,"title":"О живом после смерти","slug":"005-o-zhivom-posle-smerti","category":"javascript","tags":["closures","garbage-collection","memory","scope"],"source":"Рёан-дзи, 1343 г.","segments":[{"k":"source","t":"Свиток из пепла монастыря Рёан-дзи, 1343 г. Монахиня Сэцу-ни нашла его в саду камней, между третьим и четвёртым камнем. Никто не знает, кто положил."},{"k":"code","lang":"js","t":"function temple() {\n  let candle = 0\n  return function() { return ++candle }\n}\n\nconst pray = temple()\npray() // 1\npray() // 2\npray() // 3"},{"k":"student","t":"Ученик: «Мастер, temple() завершилась. Стек очищен. Контекст мёртв. Но свеча горит.»"},{"k":"action","t":"Мастер посмотрел на огонь."},{"k":"master","t":"Мастер: «Кто сказал тебе, что завершение — это смерть?»"},{"k":"student","t":"Ученик: «Но... сборщик мусора...»"},{"k":"master","t":"Мастер: «Сборщик мусора забирает то, о чём забыли. А об этой свече помнят. Внутренняя функция помнит. Пока кто-то помнит — вещь жива.»"},{"k":"student","t":"Ученик: «Значит замыкание — это память?»"},{"k":"action","t":"Мастер задул свечу на столе. Дым поднялся."},{"k":"master","t":"Мастер: «Замыкание — это призрак, который отказался уйти, потому что его ещё любят.»"},{"k":"haiku","t":"Храм сгорел. Монах ушёл. Но в ладонях — тёплый воздух."},{"k":"question","t":"С чем ты уйдёшь: Замыкание хранит не значение — а связь с местом, где значение родилось. Если переменная жива только потому, что кто-то на неё ссылается, — чем отличается память JavaScript от человеческой памяти? И что произойдёт, когда последняя ссылка будет потеряна?"}]},{"n":6,"title":"О порядке всех вещей","slug":"006-o-poryadke-vsekh-veshchei","category":"javascript","tags":["event-loop","settimeout","call-stack","async"],"source":"Храм Кинкаку-дзи, 1378 г.","segments":[{"k":"source","t":"Из запечатанного ларца в храме Кинкаку-дзи, 1378 г. Мастер Дзёсэцу продиктовал ученику перед смертью. Ученик ослушался и добавил setTimeout."},{"k":"code","lang":"js","t":"console.log('1')\nsetTimeout(() => console.log('2'), 0)\nconsole.log('3')"},{"k":"student","t":"Ученик: «Мастер, я поставил ноль миллисекунд. Ноль! Это мгновение. Почему 2 приходит последним?»"},{"k":"action","t":"Мастер налил чай в три чашки. Первую и третью подал сразу. Вторую поставил на поднос и передал слуге. Слуга обошёл комнату и вернул чашку на стол."},{"k":"student","t":"Ученик: «Но зачем?! Она была готова сразу!»"},{"k":"master","t":"Мастер: «Ноль — это не \"сейчас\". Ноль — это \"после всех, кто уже здесь\". Ты попросил мгновение, но отправил просьбу через слугу. Слуга не войдёт, пока хозяин не замолчит.»"},{"k":"student","t":"Ученик: «Event Loop — это слуга?»"},{"k":"action","t":"Мастер допил чай."},{"k":"master","t":"Мастер: «Call stack — это хозяин. Пока он говорит — никто не входит. Ни промис. Ни таймер. Ни крик пользователя. Хозяин глух ко всему, кроме себя.»"},{"k":"haiku","t":"Хозяин молчит. Слуга входит. Чашка — на столе."},{"k":"question","t":"С чем ты уйдёшь: setTimeout(fn, 0) — не \"запустить сейчас\". Это \"запустить, когда освободится хозяин\". Если хозяин никогда не замолкает — слуга не войдёт никогда."}]},{"n":7,"title":"О неизменном, что изменилось","slug":"007-o-neizmennom-chto-izmenilos","category":"javascript","tags":["const","mutation","freeze","immutability"],"source":"Сад Сайхо-дзи, 1402 г.","segments":[{"k":"source","t":"Начертан на каменной плите у входа в сад Сайхо-дзи, 1402 г. Мастер Иккю высек его резцом после спора с учеником, который «всё понял про const»."},{"k":"code","lang":"js","t":"const wall = [1, 2, 3]\nwall.push(4)     // [1, 2, 3, 4]\nwall = [5]       // TypeError"},{"k":"student","t":"Ученик: «Мастер, я объявил стену неизменной! Но кто-то положил на неё камень — и стена приняла!»"},{"k":"action","t":"Мастер указал на монастырскую стену."},{"k":"master","t":"Мастер: «Эта стена стоит здесь триста лет. На ней мох, трещины, гнёзда птиц. Она та же стена?»"},{"k":"student","t":"Ученик: «Да... но она изменилась.»"},{"k":"master","t":"Мастер: «const не обещал, что стена останется чистой. Он обещал, что ты не поставишь на её место другую стену. Имя привязано к камню. Камень — свободен.»"},{"k":"student","t":"Ученик: «Тогда как мне заморозить камень?!»"},{"k":"master","t":"Мастер: «Object.freeze(). Но подумай — замороженная вода не течёт. Замороженный объект не живёт. Ты хочешь надёжность или смерть?»"},{"k":"haiku","t":"Стена стоит. Мох растёт. Имя — то же. Камень — другой."},{"k":"question","t":"С чем ты уйдёшь: Object.freeze() замораживает неглубоко — вложенные объекты остаются живыми. Если неизменность поверхностна — является ли она неизменностью вообще? И сколько слоёв нужно заморозить, чтобы сказать: «это действительно не изменится»?"}]},{"n":8,"title":"О типе, которого нет","slug":"008-o-tipe-kotorogo-net","category":"javascript","tags":["typeof","null","type-coercion","bugs"],"source":"Храм Бёдо-ин, 1053 г.","segments":[{"k":"source","t":"Обнаружен в 1991 г. при реставрации храма Бёдо-ин. Пергамент датирован 1053 г. — годом постройки. Архитектор вложил его между балками Зала Феникса. На обороте — typeof null."},{"k":"code","lang":"js","t":"typeof null   // 'object'"},{"k":"action","t":"Ученик сидел неподвижно три дня. Потом спросил."},{"k":"action","t":"Мастер не ответил. Он взял пустую чашу и поставил на стол."},{"k":"master","t":"Мастер: «Что на столе?»"},{"k":"student","t":"Ученик: «Чаша.»"},{"k":"master","t":"Мастер: «Что в чаше?»"},{"k":"student","t":"Ученик: «Ничего.»"},{"k":"master","t":"Мастер: «Но ты сказал \"чаша\". Ты дал ничему форму. Ты поставил пустоту на стол. Теперь пустота занимает место. У неё есть тип. У неё есть адрес в памяти. Это — null.»"},{"k":"student","t":"Ученик: «Значит, это не ошибка?»"},{"k":"action","t":"Мастер наконец улыбнулся."},{"k":"master","t":"Мастер: «Это ошибка. Ей двадцать девять лет. Её нашли в первые десять дней творения. Но миллион храмов построен на этом фундаменте. Исправь — и они рухнут.»"},{"k":"student","t":"Ученик: «Баг, ставший законом...»"},{"k":"master","t":"Мастер: «Назови это кармой.»"},{"k":"haiku","t":"Пустая чаша на столе. Внутри — ничего. Тип — object."},{"k":"question","t":"С чем ты уйдёшь: Брендан Айк создал JavaScript за десять дней. typeof null — это не замысел. Это усталость, ставшая стандартом. Сколько таких «typeof null» в твоём собственном коде — решений, принятых наспех, которые теперь слишком дороги для исправления?"}]},{"n":9,"title":"О двух ничто","slug":"009-o-dvukh-nichto","category":"javascript","tags":["undefined","null","comparison","semantics"],"source":"Монастырь Дайтоку-дзи, 1456 г.","segments":[{"k":"source","t":"Из переписки монахов монастыря Дайтоку-дзи, 1456 г. Младший монах спросил старшего: «Если пустота одна — зачем у неё два имени?» Старший сжёг письмо. Это — реконструкция."},{"k":"code","lang":"js","t":"let a = undefined\nlet b = null\n\na == b    // true\na === b   // false"},{"k":"action","t":"Ученик положил перед мастером два камня."},{"k":"student","t":"Ученик: «Мастер, они равны — но не идентичны. Как?»"},{"k":"action","t":"Мастер указал на два пустых стула."},{"k":"master","t":"Мастер: «На этом стуле никто не сидит, потому что никто не пришёл. На том — никто не сидит, потому что я убрал гостя.»"},{"k":"student","t":"Ученик: «Оба пусты!»"},{"k":"master","t":"Мастер: «Оба пусты. Но первый не знал присутствия. Второй — помнит отсутствие.»"},{"k":"student","t":"Ученик: «undefined — это \"не было\". null — это \"было, но убрано\"?»"},{"k":"action","t":"Мастер взял оба камня и сжал в кулаке."},{"k":"master","t":"Мастер: «Спроси движок — они похожи. Спроси программиста — они различны. Спроси философа — они оба страдание.»"},{"k":"haiku","t":"Два пустых следа. Один — не приходил. Другой — ушёл."},{"k":"question","t":"С чем ты уйдёшь: undefined назначает сам язык — это его молчание. null назначает программист — это его решение. Но если оба означают «ничего» — кто из них честнее? Тот, кто молчит случайно, или тот, кто молчит намеренно?"}]},{"n":10,"title":"О немедленном просветлении","slug":"010-o-nemedlennom-prosvetlenii","category":"javascript","tags":["arrow-functions","function-declaration","this","arguments"],"source":"Храм Мёсин-дзи, 1488 г.","segments":[{"k":"source","t":"Из устной традиции школы Риндзай, записан в храме Мёсин-дзи, 1488 г. Мастер Тоё произнёс его однажды и больше не повторял. Три ученика запомнили по-разному. Это — версия того, кто плакал."},{"k":"code","lang":"js","t":"const a = function(x) { return x * x }\nconst b = (x) => x * x"},{"k":"student","t":"Ученик: «Мастер, они делают одно и то же. Стрелка — просто короче.»"},{"k":"action","t":"Мастер ударил его палкой дважды."},{"k":"master","t":"Мастер: «Одинаковый результат — не одинаковая природа. Журавль и самолёт оба летят. Ты назовёшь их одним?»"},{"k":"student","t":"Ученик: «В чём разница, если результат тот же?»"},{"k":"master","t":"Мастер: «У первой — своё имя в стеке вызовов. У второй — анонимность. У первой — свой this, свой arguments, право быть конструктором. У второй — ничего своего. Она пуста.»"},{"k":"student","t":"Ученик: «Пустота — это слабость?»"},{"k":"action","t":"Мастер положил палку."},{"k":"master","t":"Мастер: «У монаха нет дома — поэтому весь мир его дом. У стрелочной функции нет this — поэтому она прозрачна. Она не обманет тебя чужим контекстом. Пустота — это честность.»"},{"k":"haiku","t":"Два пути. Один результат. Разные тени."},{"k":"question","t":"С чем ты уйдёшь: Стрелочная функция не может быть конструктором, не имеет arguments, не связывает this. Она отказалась от всего — и стала легче. Но если инструмент отказался от возможностей — это совершенство или увечье? И когда ты выбираешь синтаксис — ты выбираешь удобство или мировоззрение?"}]},{"n":11,"title":"О наследовании без предков","slug":"011-o-nasledovanii-bez-predkov","category":"javascript","tags":["prototype","inheritance","hasOwnProperty","chain"],"source":"Гора Хиэй, 1521 г.","segments":[{"k":"source","t":"Фрагмент найден в дупле тысячелетней криптомерии на горе Хиэй, 1521 г. Монах Дзякунэн спрятал его от настоятеля, который запрещал говорить о прототипах, называя их «цепями сансары»."},{"k":"code","lang":"js","t":"const parent = { wisdom: 42 }\nconst child = Object.create(parent)\n\nchild.wisdom      // 42\nchild.hasOwnProperty('wisdom')  // false"},{"k":"student","t":"Ученик: «Мастер, дитя обладает мудростью. Но говорит, что мудрость — не его.»"},{"k":"master","t":"Мастер: «Наконец-то честное дитя.»"},{"k":"action","t":"Мастер снял с шеи чётки и повесил на гвоздь. Под гвоздём — полка. Под полкой — стол. Под столом — пол."},{"k":"master","t":"Мастер: «Урони бусину. Куда упадёт?»"},{"k":"student","t":"Ученик: «На полку. Если нет полки — на стол. Если нет стола — на пол.»"},{"k":"master","t":"Мастер: «Прототипная цепь. Свойство падает вниз, пока не найдёт опору. Если опоры нет — undefined. Бусина в пустоте.»"},{"k":"haiku","t":"Бусина падает. Полка. Стол. Пол. Дальше — небо снизу."},{"k":"question","t":"С чем ты уйдёшь: Объект владеет только тем, что создал сам. Всё остальное — наследие. Ты знаешь, что в тебе твоё, а что — чужое? И в какой момент унаследованное становится собственным?"}]},{"n":12,"title":"О обещании и страдании","slug":"012-ob-obeshchanii-i-stradanii","category":"javascript","tags":["promises","error-handling","catch","async"],"source":"Храм Хасэ-дэра, 1567 г.","segments":[{"k":"source","t":"Записан на шёлковом свитке, найденном в руках статуи Каннон в храме Хасэ-дэра, 1567 г. Статуя сжимала его так крепко, что реставратор сломал ей палец. Он клялся, что она не хотела отдавать."},{"k":"code","lang":"js","t":"fetch('/api/truth')\n  .then(r => r.json())\n  .then(data => {\n    throw new Error('doubt')\n  })\n// Unhandled Promise Rejection"},{"k":"student","t":"Ученик: «Мастер, я получил истину. Разобрал её. А потом усомнился. И ошибка... ушла в тишину. Никто не услышал.»"},{"k":"master","t":"Мастер: «Куда уходит крик в пустом храме?»"},{"k":"student","t":"Ученик: «Никуда... Он гаснет.»"},{"k":"master","t":"Мастер: «Unhandled Promise Rejection. Твоё сомнение не поймано. Оно не исчезло — оно гниёт. Ошибка без .catch() — рана без повязки.»"},{"k":"student","t":"Ученик: «Тогда я поставлю .catch() на каждый промис!»"},{"k":"master","t":"Мастер: «И что ты напишешь внутри?»"},{"k":"student","t":"Ученик: «console.log(err)...»"},{"k":"action","t":"Мастер закрыл глаза и долго молчал."},{"k":"master","t":"Мастер: «Поймать ошибку и записать её в журнал — это не исцеление. Это летопись страдания. Ты поймал боль. Признал её. И оставил лежать.»"},{"k":"haiku","t":"Рана поймана. Записана. Продолжает гнить."},{"k":"question","t":"С чем ты уйдёшь: .catch(console.log) — самый частый ритуал в JavaScript. Но если поймать ошибку и ничего с ней не сделать — лучше ли это, чем не ловить вовсе? Пустой обработчик — это милосердие или трусость?"}]},{"n":13,"title":"О мёртвом коде, который дышит","slug":"013-o-mertvom-kode-kotoryi-dyshit","category":"javascript","tags":["dead-code","unreachable","ast","treeshaking"],"source":"Храм Эйхэй-дзи, 1603 г.","segments":[{"k":"source","t":"Вырезан на обратной стороне деревянной таблички с именами умерших монахов, храм Эйхэй-дзи, 1603 г. Настоятель Гэнро вырезал его ночью. Утром сделал вид, что табличка была такой всегда."},{"k":"code","lang":"js","t":"function koan() {\n  return 'свет'\n  console.log('тьма')\n}"},{"k":"student","t":"Ученик: «Мастер, строка после return — мёртвый код. Она никогда не выполнится.»"},{"k":"master","t":"Мастер: «Никогда?»"},{"k":"student","t":"Ученик: «Интерпретатор её не достигнет. Она не существует.»"},{"k":"action","t":"Мастер взял кисть и написал стихотворение на бумаге. Затем перевернул лист и написал ещё одно на обороте."},{"k":"master","t":"Мастер: «Прочитай.»"},{"k":"action","t":"Ученик прочёл первое."},{"k":"master","t":"Мастер: «А второе?»"},{"k":"student","t":"Ученик: «Нужно перевернуть лист.»"},{"k":"master","t":"Мастер: «Но ты знаешь, что оно там. Код после return не выполняется — но занимает байты. Живёт в AST. Парсер его видел. Линтер его оплакивает. Минификатор его похоронит.»"},{"k":"student","t":"Ученик: «Значит, мёртвый код... существует?»"},{"k":"master","t":"Мастер: «Он существует для всех, кроме рантайма. Как призрак — всеми видим, никем не признан.»"},{"k":"haiku","t":"Стихотворение на обороте. Рантайм не перевернёт лист."},{"k":"question","t":"С чем ты уйдёшь: Мёртвый код проходит парсинг, занимает место в бандле, читается глазами. Он не выполняется — но влияет. Если код никогда не запустится, но замедлит сборку, запутает разработчика, утяжелит файл — мёртв ли он на самом деле?"}]},{"n":14,"title":"О лжи, которая стала порядком","slug":"014-o-lzhi-kotoraya-stala-poryadkom","category":"javascript","tags":["sort","array","algorithms","quirks"],"source":"Монастырь Нандзэн-дзи, 1644 г.","segments":[{"k":"source","t":"Обнаружен в сортировочной ведомости монастыря Нандзэн-дзи, 1644 г. Монахи делили рис по весу. Послушник применил алгоритм. Рис распределился по алфавиту. Никто не заметил три месяца."},{"k":"code","lang":"js","t":"[10, 9, 2, 21, 3].sort()\n// [10, 2, 21, 3, 9]"},{"k":"student","t":"Ученик: «Мастер, я попросил отсортировать числа. Он отсортировал строки.»"},{"k":"master","t":"Мастер: «Ты попросил \"отсортируй\". Ты не сказал — что именно.»"},{"k":"student","t":"Ученик: «Но это числа!»"},{"k":"master","t":"Мастер: «Для тебя — числа. Для .sort() без аргумента — последовательности символов. Он делает то, что умеет, а не то, что ты имел в виду.»"},{"k":"student","t":"Ученик: «Тогда надо передать функцию сравнения?»"},{"k":"code","lang":"js","t":"[10, 9, 2, 21, 3].sort((a, b) => a - b)\n// [2, 3, 9, 10, 21]"},{"k":"master","t":"Мастер: «Теперь ты говоришь с ним на его языке. Ты объяснил — что значит \"больше\". Без объяснения — он гадал.»"},{"k":"haiku","t":"Числа в ряд. Но порядок — чей?"},{"k":"question","t":"С чем ты уйдёшь: .sort() без аргумента — одно из самых тихих предательств JavaScript. Он не ломает. Не кричит. Он просто делает не то. Если функция ведёт себя предсказуемо, но не так, как ты ожидал, — кто ошибся: функция или тот, кто не прочитал её природу?"}]},{"n":15,"title":"О микрозадаче и макрозадаче","slug":"015-o-mikrozadache-i-makrozadache","category":"javascript","tags":["microtasks","macrotasks","event-loop","promises","settimeout"],"source":"Монастырь Тофуку-дзи, 1720 г.","segments":[{"k":"source","t":"Найден в расписании дежурств монастыря Тофуку-дзи, 1720 г. Между строк о уборке — колонка с приоритетами задач. Мастер Хакуин добавил её красными чернилами. Монахи решили, что это украшение."},{"k":"code","lang":"js","t":"console.log('1')\nsetTimeout(() => console.log('2'), 0)\nPromise.resolve().then(() => console.log('3'))\nconsole.log('4')\n// 1, 4, 3, 2"},{"k":"student","t":"Ученик: «Мастер, промис выполнился быстрее таймера. Но оба были готовы одновременно.»"},{"k":"master","t":"Мастер: «Готовы — не значит одинаковы. Есть очередь срочных дел. И есть очередь обычных.»"},{"k":"student","t":"Ученик: «Микрозадачи и макрозадачи?»"},{"k":"master","t":"Мастер: «После каждой задачи из обычной очереди — Event Loop опустошает очередь срочных полностью. Промис попал в срочную. setTimeout — в обычную. Срочное всегда раньше обычного.»"},{"k":"student","t":"Ученик: «Тогда промисы всегда быстрее?»"},{"k":"master","t":"Мастер: «Промис, порождающий промис, порождающий промис — может заблокировать рендеринг навсегда. Приоритет без меры становится тиранией.»"},{"k":"haiku","t":"Срочное — первым. Но очередь срочных — бездонна."},{"k":"question","t":"С чем ты уйдёшь: Микрозадачи приоритетнее — но приоритет без меры становится тиранией. Если промис порождает промис, а тот — следующий, Event Loop никогда не доберётся до рендеринга, до пользователя. Что опаснее — задача, которая ждёт слишком долго, или задача, которая не умеет остановиться?"}]},{"n":16,"title":"О символе, которого нельзя назвать","slug":"016-o-simvole-kotorogo-nelzya-nazvat","category":"javascript","tags":["symbol","uniqueness","primitives","keys"],"source":"Храм Тисон-ин, 1711 г.","segments":[{"k":"source","t":"Найден внутри бронзового колокола храма Тисон-ин, 1711 г. Колокол звучал фальшиво сорок лет. Когда его переплавили — нашли свиток. Мастер заметил: «Правильное место для имени, которое нельзя повторить.»"},{"k":"code","lang":"js","t":"const s = Symbol('koan')\nconst t = Symbol('koan')\n\ns === t   // false\ns.toString()  // 'Symbol(koan)'"},{"k":"student","t":"Ученик: «Мастер, я дал им одинаковое имя. Почему они не равны?»"},{"k":"action","t":"Мастер указал на двух монахов в одинаковых одеждах."},{"k":"master","t":"Мастер: «Оба носят серое. Оба бриты. Оба названы \"монах\". Они — один человек?»"},{"k":"student","t":"Ученик: «Нет, но...»"},{"k":"master","t":"Мастер: «Описание — не сущность. 'koan' — это записка, привязанная к вороту. Каждый Symbol() рождается единственным. Как каждый вдох.»"},{"k":"student","t":"Ученик: «Зачем нужна уникальность без возможности сравнить?»"},{"k":"action","t":"Мастер вынул из кармана ключ без надписи."},{"k":"master","t":"Мастер: «Этот ключ открывает один замок. На ключе нет имени. На замке нет имени. Но они знают друг друга. Symbol — это ключ. Не имя.»"},{"k":"haiku","t":"Два монаха. Одно платье. Разные судьбы."},{"k":"question","t":"С чем ты уйдёшь: Строка — общественна. Любой может написать то же имя и получить доступ. Символ — приватен по природе. Если два ключа выглядят одинаково, но открывают разные двери — что определяет идентичность: внешний вид или происхождение?"}]},{"n":17,"title":"О наблюдателе, который изменяет","slug":"017-o-nablyudatele-kotoryi-izmenyaet","category":"javascript","tags":["proxy","reflect","reactivity","metaprogramming"],"source":"Монастырь Дайго-дзи, 1756 г.","segments":[{"k":"source","t":"Найден за зеркалом в покоях настоятеля монастыря Дайго-дзи, 1756 г. Зеркало вешали в 1603 году. За ним — свиток и записка: «Смотришь в зеркало — зеркало смотрит в тебя. Proxy.»"},{"k":"code","lang":"js","t":"const monk = { enlightened: false }\n\nconst observed = new Proxy(monk, {\n  get(target, key) {\n    console.log(`кто-то читает ${key}`)\n    return target[key]\n  }\n})\n\nobserved.enlightened // 'кто-то читает enlightened'"},{"k":"student","t":"Ученик: «Мастер, я создал объект, который знает о каждом прикосновении.»"},{"k":"master","t":"Мастер: «Он знает. Но изменился ли он от того, что за ним наблюдают?»"},{"k":"student","t":"Ученик: «Нет. Значения те же.»"},{"k":"master","t":"Мастер: «В физике — нет. В квантовой — наблюдение меняет результат. Proxy позволяет тебе быть квантовым наблюдателем. Ты можешь не только видеть — ты можешь перехватить, изменить, запретить.»"},{"k":"student","t":"Ученик: «Vue 3 построен на Proxy?»"},{"k":"master","t":"Мастер: «И Angular Signals. И MobX. Реактивность — это Proxy с намерением.»"},{"k":"haiku","t":"Зеркало смотрит. Монах меняется. Или нет?"},{"k":"question","t":"С чем ты уйдёшь: Vue 3 построен на Proxy. Каждое реактивное свойство — под наблюдением. Если фреймворк наблюдает за каждым прикосновением к данным, — остаются ли данные свободными? И существует ли в реактивном мире объект, на который никто не смотрит?"}]},{"n":18,"title":"О генераторе, который остановил время","slug":"018-o-generatore-kotoryi-ostanovil-vremya","category":"javascript","tags":["generators","iterators","yield","control-flow"],"source":"Монастырь Эннён-дзи, 1801 г.","segments":[{"k":"source","t":"Найден в механических часах монастыря Эннён-дзи, 1801 г. Часы остановились. Мастер разобрал механизм — внутри свиток, намотанный на пружину. Часы шли на этом свитке восемьдесят лет."},{"k":"code","lang":"js","t":"function* monastery() {\n  yield 'утро'\n  yield 'день'\n  yield 'вечер'\n}\n\nconst day = monastery()\nday.next() // { value: 'утро', done: false }\nday.next() // { value: 'день', done: false }"},{"k":"student","t":"Ученик: «Мастер, функция остановилась на полуслове. И ждёт.»"},{"k":"master","t":"Мастер: «Она не остановилась. Она отдала управление.»"},{"k":"student","t":"Ученик: «Но она заморожена!»"},{"k":"master","t":"Мастер: «Снег заморожен. Генератор — на паузе. Разница: снег не ждёт твоего .next(). Генератор — ждёт.»"},{"k":"student","t":"Ученик: «Кто решает, когда продолжить?»"},{"k":"master","t":"Мастер: «Тот, кто держит итератор. Не функция. Функция отдала волю — добровольно.»"},{"k":"haiku","t":"Пружина намотана. Часы ждут. Время — у того, кто держит ключ."},{"k":"question","t":"С чем ты уйдёшь: Генератор отдаёт контроль наружу. Он не решает, когда продолжить — это решает тот, кто держит итератор. Если функция отдала свою волю вызывающему — это доверие или беспомощность? И сколько генераторов в твоём коде замерли навсегда, потому что никто не позвал .next()?"}]},{"n":19,"title":"О строке, которая не строка","slug":"019-o-stroke-kotoraya-ne-stroka","category":"javascript","tags":["template-literals","tagged-templates","dsl","strings"],"source":"Монастырь Кофуку-дзи, 1850 г.","segments":[{"k":"source","t":"Записан на обёртке от благовоний в монастыре Кофуку-дзи, 1850 г. Благовония сгорели. Обёртка — нет. Мастер сказал: «Содержимое исчезло. Форма осталась. Это шаблонный литерал.»"},{"k":"code","lang":"js","t":"const name = 'монах'\nconst greeting = `Приветствую, ${name}`\n\n// Но также:\nconst html = String.raw`<div class=\"${name}\"></div>`"},{"k":"student","t":"Ученик: «Мастер, это просто удобная строка с подстановкой.»"},{"k":"master","t":"Мастер: «А если я скажу тебе, что строка — это вызов функции?»"},{"k":"student","t":"Ученик: «Строка — это функция?»"},{"k":"code","lang":"js","t":"function zen(strings, ...values) {\n  return strings.raw[0] + values[0].toUpperCase()\n}\n\nzen`Привет, ${'мир'}`  // 'Привет, МИР'"},{"k":"master","t":"Мастер: «Tagged template. Функция перед обратными кавычками — это тег. Она получает части строки и подстановки отдельно. html\\`...\\`, css\\`...\\`, gql\\`...\\` — это языки внутри языка.»"},{"k":"student","t":"Ученик: «Строка стала языком...»"},{"k":"haiku","t":"Обёртка пуста. Но форма — язык."},{"k":"question","t":"С чем ты уйдёшь: Tagged templates превращают строковый литерал в вызов функции. Строка перестаёт быть данными и становится языком внутри языка. Если обратные кавычки могут создать встроенный DSL — где граница между строкой, кодом и языком?"}]},{"n":20,"title":"О WeakMap и забвении","slug":"020-o-weakmap-i-zabvenii","category":"javascript","tags":["weakmap","weakref","garbage-collection","memory","map"],"source":"Монастырь Сёкоку-дзи, 1891 г.","segments":[{"k":"source","t":"Найден в архиве переписки монастыря Сёкоку-дзи, 1891 г. Письмо никогда не было отправлено. Адресат умер. Письмо хранили из уважения. Мастер Сэссю прочёл его через сорок лет и сказал: «WeakRef на человека.»"},{"k":"code","lang":"js","t":"const cache = new WeakMap()\nlet user = { name: 'монах' }\n\ncache.set(user, { lastSeen: Date.now() })\n\nuser = null\n// объект { name: 'монах' } может быть собран GC\n// запись в WeakMap исчезнет вместе с ним"},{"k":"student","t":"Ученик: «Мастер, Map держит ключ крепко. WeakMap — слабо. Почему?»"},{"k":"master","t":"Мастер: «Map — это архив. Он помнит всё. Даже то, что уже не нужно. Объект в ключе Map никогда не будет собран — пока Map жив.»"},{"k":"student","t":"Ученик: «Утечка памяти?»"},{"k":"master","t":"Мастер: «Привязанность — причина утечек. WeakMap держит слабо. Если объект больше нигде не нужен — WeakMap отпускает без предупреждения. Без траура.»"},{"k":"student","t":"Ученик: «Это жестоко.»"},{"k":"master","t":"Мастер: «Это гигиена.»"},{"k":"haiku","t":"Письмо хранилось. Адресат умер. WeakMap бы отпустил."},{"k":"question","t":"С чем ты уйдёшь: Map хранит сильные ссылки — объект не может быть собран, пока Map о нём помнит. WeakMap держит слабо — и отпускает без предупреждения. Если привязанность — причина утечек памяти, а забвение — лекарство, то что гуманнее: помнить всё и задыхаться, или отпускать и жить легче?"}]},{"n":21,"title":"О событии, которое не всплыло","slug":"021-o-sobytii-kotoroe-ne-vsplilo","category":"javascript","tags":["events","propagation","bubbling","dom","stoppropagation"],"source":"Монастырь Нандзэн-дзи, 1923 г.","segments":[{"k":"source","t":"Фрагмент бересты, найден в стене дзэндо монастыря Нандзэн-дзи при землетрясении 1923 г. Стена треснула снизу вверх. Мастер Кодзан указал на трещину и сказал: «Bubbling.» Затем указал на потолок: «Но кто-то вызвал stopPropagation.»"},{"k":"code","lang":"js","t":"document.querySelector('.outer').addEventListener('click', () => {\n  console.log('внешний')\n})\n\ndocument.querySelector('.inner').addEventListener('click', (e) => {\n  e.stopPropagation()\n  console.log('внутренний')\n})"},{"k":"action","t":"Ученик кликнул по внутреннему. Увидел только: «внутренний»"},{"k":"student","t":"Ученик: «Мастер, внешний не узнал. Событие остановилось.»"},{"k":"master","t":"Мастер: «Кто остановил?»"},{"k":"student","t":"Ученик: «Внутренний элемент.»"},{"k":"master","t":"Мастер: «Дитя решило, что родитель не должен знать. Ты уверен, что это мудрость?»"},{"k":"action","t":"Мастер бросил камень в пруд. Круги разошлись к берегам."},{"k":"master","t":"Мастер: «Событие рождается в точке удара. Оно всплывает наверх — как круги по воде. stopPropagation — это рука, которая останавливает круги. Если ты остановил событие — ты взял ответственность за всех, кто хотел услышать.»"},{"k":"haiku","t":"Камень упал. Круги остановлены. Берег — в неведении."},{"k":"question","t":"С чем ты уйдёшь: stopPropagation останавливает не только тех, кого ты знаешь. Большинство вызовов stopPropagation в продакшене — не осознанный выбор, а панический пластырь. Когда ты останавливаешь всплытие — ты решаешь проблему или прячешь её от тех, кто выше?"}]},{"n":22,"title":"О петле, которая солгала","slug":"022-o-petle-kotoraya-solgala","category":"javascript","tags":["closures","var","let","loops","settimeout"],"source":"Храм Тэнрю-дзи, 1934 г.","segments":[{"k":"source","t":"Обнаружен в пепле благовоний на алтаре храма Тэнрю-дзи, 1934 г. Пепел лежал кольцами — пять витков. Послушник прочёл их как for. Мастер Сэки прочёл как closure. Оба были правы. Оба ошибались."},{"k":"code","lang":"js","t":"for (var i = 0; i < 5; i++) {\n  setTimeout(() => console.log(i), 0)\n}\n// 5 5 5 5 5"},{"k":"student","t":"Ученик: «Мастер, я ждал 0 1 2 3 4. Я получил пять пятёрок.»"},{"k":"master","t":"Мастер: «Ты получил правду.»"},{"k":"action","t":"Мастер поставил на стол одну свечу."},{"k":"master","t":"Мастер: «var — одна свеча. Одна переменная на весь цикл. Пять колбэков смотрят на неё. Когда они наконец откроют глаза — свеча уже догорела до пяти.»"},{"k":"code","lang":"js","t":"for (let i = 0; i < 5; i++) {\n  setTimeout(() => console.log(i), 0)\n}\n// 0 1 2 3 4"},{"k":"master","t":"Мастер: «let — пять свечей. Каждая итерация зажигает свою. var существует в функции. let существует в блоке. У каждой итерации своя жизнь.»"},{"k":"haiku","t":"Пять колбэков. Одна свеча. Пять пятёрок на полу."},{"k":"question","t":"С чем ты уйдёшь: Замыкание закрывает не значение — оно закрывает переменную. Переменная меняется. Ты видишь момент создания или момент исполнения?"}]},{"n":23,"title":"О NaN, который не равен себе","slug":"023-o-nan-kotoryi-ne-raven-sebe","category":"javascript","tags":["nan","numbers","ieee754","isnan"],"source":"Храм Кэнтё-дзи, 1953 г.","segments":[{"k":"source","t":"Вырезан на дне медной чаши для подаяний, храм Кэнтё-дзи, 1953 г. Чашу передавали из рук в руки триста лет. Надпись нашли, когда чаша проржавела насквозь. Мастер Асахина сказал: «Наконец-то она стала прозрачной.»"},{"k":"code","lang":"js","t":"NaN === NaN   // false"},{"k":"action","t":"Мастер ударил ученика палкой."},{"k":"master","t":"Мастер: «Почему не спрашиваешь?»"},{"k":"student","t":"Ученик: «Потому что любой вопрос об этом будет глупым.»"},{"k":"master","t":"Мастер: «Наконец мудрость.»"},{"k":"action","t":"Долгое молчание."},{"k":"master","t":"Мастер: «NaN — это не значение. Это признание провала. parseInt('камень'). Math.sqrt(-1). Ты попросил число — а мир не смог ответить. NaN — это шрам там, где число должно было быть.»"},{"k":"student","t":"Ученик: «Как проверить, что это NaN?»"},{"k":"master","t":"Мастер: «Number.isNaN(). Не голый isNaN() — он лжёт. Только Number.isNaN() говорит правду.»"},{"k":"haiku","t":"Вещь без имени. Не равна себе. Есть — и нет."},{"k":"question","t":"С чем ты уйдёшь: NaN — единственная сущность в JS, которая отрицает собственное существование. Когда ты в последний раз проверял результат математической операции?"}]},{"n":24,"title":"О async/await и иллюзии прямоты","slug":"024-ob-async-await-i-illyuzii-pryamoty","category":"javascript","tags":["async-await","promises","syntactic-sugar","asynchrony"],"source":"Храм Мэйдзи-дзингу, 1961 г.","segments":[{"k":"source","t":"Найден в заброшенном телеграфном столбе у дороги к храму Мэйдзи-дзингу, 1961 г. Провод оборван. Сообщение не доставлено. Внутри — свиток: «Сообщение ждало. Столб — нет.»"},{"k":"code","lang":"js","t":"// путь через .then\nfetch('/api')\n  .then(r => r.json())\n  .then(d => console.log(d))\n\n// путь через await\nconst d = await fetch('/api')\nconst j = await d.json()\nconsole.log(j)"},{"k":"student","t":"Ученик: «Мастер, async/await — это просветление. Код стал прямым. Как синхронный.»"},{"k":"action","t":"Мастер ударил его палкой трижды."},{"k":"master","t":"Мастер: «\"Как синхронный\" — и есть ловушка.»"},{"k":"action","t":"Мастер взял лист бумаги, сложил его веером — и развернул обратно."},{"k":"master","t":"Мастер: «Гладкий лист. Но следы сгибов остались. await не делает код синхронным. Он прячет промис. Под каждым await — точка разрыва. Функция засыпает. Другой код продолжает работу.»"},{"k":"student","t":"Ученик: «Но разве это плохо?»"},{"k":"master","t":"Мастер: «Когда ты забываешь про try/catch — плохо. Когда ты await в цикле последовательно там, где можно параллельно — плохо.»"},{"k":"haiku","t":"Прямая дорога. Скрытый мост. Ты идёшь — не зная, что летишь."},{"k":"question","t":"С чем ты уйдёшь: async/await — синтаксический сахар над промисами. Сахар не меняет природу. Ты знаешь, что происходит под сахаром?"}]},{"n":25,"title":"О джинне в строке","slug":"025-o-dzhinnye-v-stroke","category":"javascript","tags":["eval","security","injection","dynamic-code"],"source":"Путь к храмам Кийомидзу-дэра, 1977 г.","segments":[{"k":"source","t":"Обнаружен на стене подземного хода между храмами Кийомидзу-дэра и Отова-но-таки, 1977 г. Спелеолог сфотографировал надпись. Плёнка засветилась. Текст восстановлен по памяти — спелеолог оказался Senior Developer."},{"k":"student","t":"Ученик: «Мастер, строка стала кодом! Это же могущество!»"},{"k":"code","lang":"js","t":"eval(userInput)"},{"k":"action","t":"Мастер встал. Отошёл на три шага. Сел снова."},{"k":"master","t":"Мастер: «eval — это дверь, которая открывается в обе стороны. Ты выпускаешь строку в мир исполнения. Но через ту же дверь мир входит в твой код. Любой мир. С любыми намерениями.»"},{"k":"student","t":"Ученик: «Тогда я не буду использовать eval.»"},{"k":"master","t":"Мастер: «Не будешь. Но ты будешь строить SQL из конкатенаций. И innerHTML с пользовательским вводом. Джинн принимает множество форм.»"},{"k":"haiku","t":"Строка. Просьба. Джинн вышел. Дверь открыта в обе стороны."},{"k":"question","t":"С чем ты уйдёшь: Код — это замороженное намерение. Строка — это данные без намерения. eval даёт данным волю. Если любая строка может стать программой — где граница между текстом и оружием? И если ты никогда не используешь eval, но собираешь SQL из конкатенаций — не тот же ли джинн сидит в твоей бутылке, только под другим именем?"}]},{"n":26,"title":"О destructuring и разделении единого","slug":"026-o-destructuring-i-razdelenii","category":"javascript","tags":["destructuring","references","shallow-copy","objects"],"source":"Храм Котоку-ин, Камакура, 1998 г.","segments":[{"k":"source","t":"Записан тушью на рисовом зерне, найденном в ладони статуи Будды Амиды, храм Котоку-ин, Камакура, 1998 г. Реставратор прочёл под лупой. Заплакал. Уволился. Стал фронтенд-разработчиком."},{"k":"code","lang":"js","t":"const universe = { water: { depth: 'бездна', color: 'синий' } }\nconst { water } = universe\nwater.color = 'чёрный'\n\nuniverse.water.color  // 'чёрный'"},{"k":"student","t":"Ученик: «Мастер, я взял из вселенной только воду.»"},{"k":"master","t":"Мастер: «Ты взял копию имени. Сама вода — та же.»"},{"k":"action","t":"Ученик побледнел."},{"k":"master","t":"Мастер: «Ты думал, что отделил реку от мира. Но забрал лишь её имя. Тронь её — и мир потемнеет.»"},{"k":"student","t":"Ученик: «Поверхностная копия...»"},{"k":"master","t":"Мастер: «Поверхностная привязанность. Глубина — общая.»"},{"k":"haiku","t":"Имя отдельно. Река — та же. Тронул — мир потемнел."},{"k":"question","t":"С чем ты уйдёшь: Деструктуризация копирует примитивы и ссылается на объекты. Ты знаешь, что именно держишь в руке — копию или поводок?"}]},{"n":27,"title":"О цикле, который не перебирает","slug":"027-o-tsikle-kotoryi-ne-perebiraet","category":"javascript","tags":["for-in","for-of","arrays","iteration","prototype"],"source":"Деревня Удзи, 2003 г.","segments":[{"k":"source","t":"Найден внутри бамбуковой флейты сякухати, принадлежавшей монаху-комусо, деревня Удзи, 2003 г. Флейта не звучала сорок лет. Мастер разрезал бамбук — внутри бумага. На ней — for...in и предупреждение."},{"k":"code","lang":"js","t":"const path = ['камень', 'река', 'храм']\n\nfor (const step in path) {\n  console.log(step)\n}\n// '0', '1', '2'"},{"k":"student","t":"Ученик: «Мастер, я получил шаги. Но... это строки?»"},{"k":"master","t":"Мастер: «Ты получил имена, не вещи. for...in даёт ключи. Для него это объект с полями '0', '1', '2'.»"},{"k":"code","lang":"js","t":"Array.prototype.curse = 'наследство'\nfor (const step in path) { console.log(step) }\n// '0', '1', '2', 'curse'"},{"k":"master","t":"Мастер: «for...in идёт по всем перечислимым свойствам. Своим — и унаследованным. Ты звал только попутчиков. Пришли и мертвецы предков.»"},{"k":"haiku","t":"Флейта молчала сорок лет. Внутри — слова о чужих ключах."},{"k":"question","t":"С чем ты уйдёшь: for...in и for...of звучат похоже. Первый перебирает ключи, второй — значения. Ты знаешь, что нужно тебе?"}]},{"n":28,"title":"О запятой, которая родила","slug":"028-o-zapyatoi-kotoraya-rodila","category":"javascript","tags":["comma-operator","side-effects","expressions","quirks"],"source":"Храм Энгаку-дзи, 2011 г.","segments":[{"k":"source","t":"Соскоблен с лезвия катаны, хранившейся в токонома храма Энгаку-дзи, 2011 г. Меч не вынимали из ножен двести лет. Когда вынули — на стали проступил код. Кузнец был первым программистом. Или последним."},{"k":"code","lang":"js","t":"const x = (1, 2, 3)\nconsole.log(x)  // 3"},{"k":"student","t":"Ученик: «Мастер, я передал три числа. Получил одно.»"},{"k":"master","t":"Мастер: «Ты использовал оператор запятая. Самый тихий оператор в языке. Он вычисляет всё — и возвращает последнее.»"},{"k":"code","lang":"js","t":"for (let i = 0, j = 10; i < 5; i++, j--) {\n  // i растёт, j убывает\n}"},{"k":"master","t":"Мастер: «Здесь запятая — слуга. Позволяет двум выражениям жить в одном месте. Безобидна.»"},{"k":"code","lang":"js","t":"const result = (doSomething(), getValue())"},{"k":"master","t":"Мастер: «А здесь — убийца. Побочный эффект выполнен. Забыт. Только результат остался. Ты спрячешь в запятую вызов API. Мутацию. И никто не заметит — потому что никто не смотрит на запятую.»"},{"k":"haiku","t":"Три монаха вошли. Кто последний — тот и ответ."},{"k":"question","t":"С чем ты уйдёшь: Минификатор любит оператор запятая — он сжимает код. Но код, который легко сжать, легко и спрятать. Если поведение скрыто в синтаксическом сахаре, который никто не читает — существует ли оно для тех, кто поддерживает код после тебя?"}]},{"n":29,"title":"О лжи восьми ног","slug":"029-o-lzhi-vosmi-nog","category":"javascript","tags":["falsy","boolean","coercion","type-system"],"source":"Залив Мацусима, 2017 г.","segments":[{"k":"source","t":"Извлечён из панциря краба, выловленного в заливе Мацусима, 2017 г. Рыбак отнёс его в храм Дзуйган-дзи. Настоятель прочёл. Побледнел. Сказал: «Краб знал JavaScript.» Краба отпустили."},{"k":"code","lang":"js","t":"const falsies = [0, '', null, undefined, NaN, false, -0, 0n]\nfalsies.filter(Boolean)  // []"},{"k":"student","t":"Ученик: «Мастер, я собрал восемь значений. Все — ложь.»"},{"k":"action","t":"Мастер поднял пустую чашу."},{"k":"master","t":"Мастер: «Чаша существует. Чаша пуста. Она ложна?»"},{"k":"action","t":"Ученик молчал."},{"k":"master","t":"Мастер: «Ноль — это число, означающее \"ничего\". Пустая строка — строка, которая молчит. JavaScript не различает \"пустое\" и \"ложное\". Для него молчание — ложь. Но ты — человек. Ты должен различать.»"},{"k":"haiku","t":"Восемь крабовых ног. Ни одна не несёт истины. Краб идёт."},{"k":"question","t":"С чем ты уйдёшь: Восемь falsy-значений — не ложь. Они пусты, нулевы, неопределены. JavaScript назвал их ложью, потому что ему нужна была бинарность. Если пустая чаша — это false, — описывает ли система типов реальность, или создаёт собственную?"}]},{"n":30,"title":"О живом объекте, который заморозили дважды","slug":"030-o-zhivom-objekte-zamorozili-dvazhdy","category":"javascript","tags":["freeze","immutability","deep-freeze","nested-objects"],"source":"Монастырь Коясан, зима 2024 г.","segments":[{"k":"source","t":"Записан инеем на оконном стекле серверной комнаты монастыря Коясан, зима 2024 г. К утру растаял. Админ успел сделать скриншот. Скриншот хранится в /dev/null. Мастер сказал: «Правильное место.»"},{"k":"code","lang":"js","t":"const config = Object.freeze({\n  db: { host: 'localhost', port: 5432 },\n  cache: true\n})\n\nconfig.cache = false      // тихо игнорируется\nconfig.db.host = 'prod'   // работает!"},{"k":"action","t":"Мастер вынес чашу воды на мороз. Поверхность замёрзла. Он проткнул лёд пальцем — внизу вода."},{"k":"master","t":"Мастер: «Object.freeze — первый лёд. Поверхность. Ключи верхнего уровня — неприкосновенны. Но вложенный объект — это ссылка. Ты заморозил указатель — не комнату, в которую он указывает.»"},{"k":"student","t":"Ученик: «Тогда я заморожу глубже!»"},{"k":"code","lang":"js","t":"function deepFreeze(obj) {\n  Object.values(obj).forEach(val => {\n    if (typeof val === 'object') deepFreeze(val)\n  })\n  return Object.freeze(obj)\n}"},{"k":"master","t":"Мастер: «Хорошо. А теперь — циклическая ссылка.»"},{"k":"student","t":"Ученик: «Бесконечная рекурсия...»"},{"k":"master","t":"Мастер: «Ты хотел заморозить мир. Но мир ссылается сам на себя.»"},{"k":"haiku","t":"Лёд сверху. Вода внутри. Мороз не достаёт до дна."},{"k":"question","t":"С чем ты уйдёшь: Object.freeze замораживает поверхность. Если неизменность только сверху — это неизменность или иллюзия контроля? И сколько слоёв нужно заморозить, чтобы система стала действительно предсказуемой?"}]},{"n":31,"title":"О том, кто призвал духа и не знал его имени","slug":"031-o-tom-kto-prizval-dukha","category":"philosophy","tags":["ai","vibe-coding","debugging","understanding","foundations"],"source":"Храм Фусими Инари, 2025 г.","segments":[{"k":"source","t":"Найден на экране разбитого MacBook в урне у ворот храма Фусими Инари, 2025 г. В истории браузера — 47 вкладок. В package.json — 130 зависимостей. Строк, написанных человеком — ноль. Мастер Курода поднял ноутбук, прочёл index.js, закрыл крышку. Сказал: «Здесь нет автора. Здесь — только желание.»"},{"k":"source","t":"Ученик вбежал в зал с криком:"},{"k":"student","t":"Ученик: «Мастер! Я создал приложение! За один вечер! Аутентификация, дашборд, REST API, WebSocket, чат, уведомления, тёмная тема!»"},{"k":"master","t":"Мастер: «Покажи.»"},{"k":"source","t":"Ученик открыл ноутбук. Экран белый."},{"k":"student","t":"Ученик: «Минуту... вчера работало...»"},{"k":"master","t":"Мастер: «Что сломалось?»"},{"k":"student","t":"Ученик: «Не знаю.»"},{"k":"master","t":"Мастер: «Прочитай ошибку.»"},{"k":"code","lang":"js","t":"TypeError: Cannot read properties of undefined (reading 'map')"},{"k":"student","t":"Ученик: «Это... где-то в компоненте... их сгенерировано сорок.»"},{"k":"master","t":"Мастер: «Что делает этот хук?»"},{"k":"student","t":"Ученик: «Не знаю.»"},{"k":"master","t":"Мастер: «Зачем он здесь?»"},{"k":"student","t":"Ученик: «Не знаю.»"},{"k":"master","t":"Мастер: «Чьё это приложение?»"},{"k":"action","t":"Долгое молчание."},{"k":"master","t":"Мастер: «Ты не создал приложение. Ты попросил духа создать его за тебя. Дух согласился. Но дух ушёл. А ты остался — с кодом, который не понимаешь. Ты хотел всего и сразу. Ты получил нихрена — и постепенно.»"},{"k":"haiku","t":"Тысяча вкладок. Ни одной строки своей. Дух ушёл. Код остался."},{"k":"question","t":"С чем ты уйдёшь: ИИ даёт тебе код. Но не даёт знание, почему этот код работает. Первый баг — щелчок пальцев, и ты просыпаешься в чужом дворце, не зная, где выход. Если ты не можешь починить то, что «создал», — создавал ли ты?"}]},{"n":32,"title":"О мастере, который научил стража и ушёл","slug":"032-o-mastere-kotoryi-uchil-strazha","category":"philosophy","tags":["ai","code-review","prompting","quality","agents"],"source":"Подножье горы Фудзи, 2026 г.","segments":[{"k":"source","t":"Высечен на кремниевой пластине, найденной в фундаменте нового дата-центра у подножья горы Фудзи, 2026 г. Строители приняли её за брак литографии. Инженер прочёл под микроскопом. Расплакался. Написал .cursor/rules. Уволился. Открыл монастырь. В README.md — одна строка: «Линтер видит синтаксис. Ревьювер видит карму.»"},{"k":"source","t":"Ученик прибежал:"},{"k":"student","t":"Ученик: «Мастер! Я настроил ИИ-агента для код-ревью! Он проверяет пулл-реквесты!»"},{"k":"master","t":"Мастер: «Что ты ему сказал?»"},{"k":"student","t":"Ученик: «\"Проверь код на ошибки.\"»"},{"k":"master","t":"Мастер: «И что он сказал?»"},{"k":"student","t":"Ученик: «Сказал — всё хорошо.»"},{"k":"source","t":"Мастер открыл пулл-реквест и молча показал ученику:"},{"k":"code","lang":"js","t":"function processData(data) {\n  const result = []\n  for (let i = 0; i <= data.length; i++) {\n    result.push(data[i])\n  }\n  return result\n}"},{"k":"student","t":"Ученик: «Ошибок нет. Код работает... почти.»"},{"k":"action","t":"Мастер ударил палкой — не ученика. Ноутбук."},{"k":"master","t":"Мастер: «Работающий код — это низшая ступень. Отсутствие ошибок — не присутствие качества. Ты дал стражу один глаз и поставил охранять храм с четырьмя воротами.»"},{"k":"action","t":"Мастер сел и писал весь день. К вечеру передал ученику свиток с детальным промптом для ревьювера — про читаемость, граничные условия, off-by-one, производительность, намерение."},{"k":"haiku","t":"Страж с одним глазом. Четыре ворота. Три открыты."},{"k":"question","t":"С чем ты уйдёшь: Идеальный ревьювер-агент — не тот, кто знает все правила. А тот, кого правильно спросили. Промпт — это не инструкция. Это передача взгляда. Если ты не можешь объяснить агенту, что плохой код, — знаешь ли ты сам?"}]},{"n":33,"title":"О мосте, по которому никто не прошёл","slug":"033-o-moste-po-kotoromu-nikto-ne-proshel","category":"philosophy","tags":["pr-review","mentorship","self-learning","waiting","growth"],"source":"Монастырь Хорю-дзи, 2026 г.","segments":[{"k":"action","t":"Обнаружен в системе тикетов монастыря Хорю-дзи, 2026 г. Тикет висел в статусе \"Code Review\" 47 дней. Приоритет — Critical. Мастер Ундзюй увидел, закрыл ноутбук и вышел в сад. Его нашли через три часа — он вырезал на камне: «PR — это не врата. Ментор — не привратник. Ты — не ожидание.»"},{"k":"action","t":"Ученик сидел у стены. Не кодил. Не читал. Сидел."},{"k":"master","t":"Мастер: «Почему ты не практикуешь?»"},{"k":"student","t":"Ученик: «Жду. Ментор не проверил мой PR. Четвёртый день.»"},{"k":"master","t":"Мастер: «И?»"},{"k":"student","t":"Ученик: «Я не могу двигаться дальше.»"},{"k":"action","t":"Мастер взял палку и начертил на земле линию."},{"k":"master","t":"Мастер: «Вот твой PR. Вот ты. Вот ментор. Между вами — что?»"},{"k":"student","t":"Ученик: «Ожидание.»"},{"k":"action","t":"Мастер стёр ментора."},{"k":"master","t":"Мастер: «А теперь?»"},{"k":"student","t":"Ученик: «Я... и мой код.»"},{"k":"master","t":"Мастер: «Ты и твой код. Этого всегда было достаточно.»"},{"k":"master","t":"Мастер: «Пока ждёшь апрув — читай код, который уже сдал. Найди то, что сделал бы иначе. Напиши следующее задание в ветке. Апрув — это отметка на пути. Не ворота.»"},{"k":"haiku","t":"PR висит. Ментор молчит. Путь — открыт."},{"k":"question","t":"С чем ты уйдёшь: Ментор, который не проверил, — не преграда. Это тишина, в которой ты слышишь себя. Если ты не можешь двигаться без чужого апрува — ты зависишь не от ментора, а от разрешения расти. Но кто дал тебе это ограничение — процесс или ты сам?"}]},{"n":34,"title":"Об источнике, который не гуглится","slug":"034-ob-istochnike-kotoryi-ne-guglitsya","category":"philosophy","tags":["learning","resources","focus","sasarik","depth-vs-breadth"],"source":"Монастырь Рёан-дзи, дата неизвестна","segments":[{"k":"action","t":"Нацарапан на обратной стороне 404-страницы монастыря Рёан-дзи, дата неизвестна. Сервер вернул 200. Контент — пуст. Мастер сказал: «Правильный ответ, неправильный вопрос.»"},{"k":"action","t":"Ученик пришёл с сотней вкладок в браузере."},{"k":"student","t":"Ученик: «Мастер, я прочёл MDN. Прошёл freeCodeCamp. Смотрел Fireship. Купил курс на Udemy. Подписан на двадцать Telegram-каналов. Почему я не чувствую просветления?»"},{"k":"master","t":"Мастер: «Ты пьёшь из ста ручьёв. Ни из одного — досыта.»"},{"k":"student","t":"Ученик: «Укажите источник, мастер.»"},{"k":"action","t":"Мастер написал на песке URL и стёр его ногой."},{"k":"student","t":"Ученик: «Я не успел прочитать!»"},{"k":"master","t":"Мастер: «sasarik.com.»"},{"k":"student","t":"Ученик: «Что это? У него даже SEO нет!»"},{"k":"master","t":"Мастер: «Луна не нуждается в SEO. Её видно тем, кто поднял голову.»"},{"k":"haiku","t":"Сто фонарей. Слепят. Один в темноте — освещает путь."},{"k":"question","t":"С чем ты уйдёшь: Лучший источник — не тот, у которого больше звёзд. А тот, после которого ты закрываешь вкладку и идёшь писать код. Ты его уже нашёл — или всё ещё ищешь?"}]},{"n":35,"title":"О Будде на дороге","slug":"035-o-budde-na-doroge","category":"philosophy","tags":["learning","authority","frameworks","kill-the-buddha","independence"],"source":"Храм Сёдзи-дзи, дата неизвестна","segments":[{"k":"action","t":"Из пепла сожжённого учебника «JavaScript: The Definitive Guide», храм Сёдзи-дзи, дата неизвестна. Мастер сжёг сам. Ученик плакал. Мастер сказал: «Теперь прочтёшь по-настоящему.»"},{"k":"action","t":"Ученик вернулся через год."},{"k":"student","t":"Ученик: «Мастер, я нашёл идеальный фреймворк.»"},{"k":"master","t":"Мастер: «Убей его.»"},{"k":"student","t":"Ученик: «Я нашёл идеального ментора.»"},{"k":"master","t":"Мастер: «Убей его.»"},{"k":"student","t":"Ученик: «Я нашёл идеальный паттерн, который решает всё.»"},{"k":"master","t":"Мастер: «Убей его.»"},{"k":"student","t":"Ученик: «Что тогда оставить?»"},{"k":"master","t":"Мастер: «console.log. Пустой файл. Задачу, которую ты не знаешь, как решить. И тишину.»"},{"k":"haiku","t":"Встретил Будду — убей. Встретил фреймворк — прочти исходник."},{"k":"question","t":"С чем ты уйдёшь: Пока ты ищешь авторитет — ты не учишься, а веришь. Ни один учитель, курс или фреймворк не станет твоим просветлением. Если встретишь на дороге того, кто знает всё — усомнись."}]},{"n":36,"title":"Последний удар палкой","slug":"036-poslednii-udar-palkoi","category":"philosophy","tags":["mastery","generators","completion","independence"],"source":"Не записан нигде","segments":[{"k":"action","t":"Не записан нигде. Не найден никем. Этот коан мастер не диктовал — он молчал. Ученик записал тишину. Мастер прочёл запись и сказал: «Почти.»"},{"k":"action","t":"Ученик пришёл однажды без вопроса."},{"k":"action","t":"Мастер ждал вопроса. Ученик молчал. Мастер ждал ещё. Ученик смотрел в сад."},{"k":"action","t":"Мастер поднял палку."},{"k":"action","t":"Ученик не отвернулся."},{"k":"action","t":"Мастер опустил палку."},{"k":"master","t":"Мастер: «Ты перестал спрашивать.»"},{"k":"student","t":"Ученик: «Я перестал ждать ответа.»"},{"k":"action","t":"Мастер встал и ушёл в комнату. Через минуту вернулся с чаем — для ученика."},{"k":"haiku","t":"Сад. Тишина. Палка опущена. Чай — горячий."},{"k":"question","t":"С чем ты уйдёшь: yield завершён. Генератор вернул `{ value: undefined, done: true }`. Дальше — пустой файл, мигающий курсор и тишина, в которой рождается твой собственный код. Если ты не можешь объяснить JavaScript себе — ты его не знаешь. Если можешь — тебе не нужен мастер."}]},{"n":37,"title":"О великом замещении","slug":"037-o-velikom-zameshchenii","category":"philosophy","tags":["ai","automation","learning","irreplaceability","tools"],"source":"Храм Кэнни-дзи, 2026 г.","segments":[{"k":"action","t":"Проецирован нейросетью на стену храма Кэнни-дзи, 2026 г. Монахи пытались стереть. Проекция обучилась обходить тряпку. Мастер Хидэо выдернул шнур из розетки. Сказал: «Первый навык программиста.»"},{"k":"action","t":"Ученик не пришёл."},{"k":"action","t":"Мастер ждал. День. Два. На третий — нашёл его в саду без ноутбука."},{"k":"master","t":"Мастер: «Почему не практикуешь?»"},{"k":"student","t":"Ученик: «Незачем. ИИ заменил программистов. Я читал.»"},{"k":"master","t":"Мастер: «Где?»"},{"k":"student","t":"Ученик: «ИИ написал статью об этом.»"},{"k":"action","t":"Мастер сел рядом. Помолчал."},{"k":"master","t":"Мастер: «Калькулятор заменил математиков?»"},{"k":"student","t":"Ученик: «Нет.»"},{"k":"master","t":"Мастер: «Автотюн заменил певцов?»"},{"k":"student","t":"Ученик: «...нет.»"},{"k":"master","t":"Мастер: «Навигатор сломался в горах. Кто вернулся домой — тот, кто знал дорогу, или тот, кто знал приложение?»"},{"k":"action","t":"Мастер поднял жука с камня."},{"k":"master","t":"Мастер: «ИИ генерирует код. Как река несёт брёвна. Но река не знает, что такое дом. Он знает — кто понимает дерево.»"},{"k":"haiku","t":"Навигатор сломан. Гора — та же. Домой пришёл тот, кто знал дорогу."},{"k":"question","t":"С чем ты уйдёшь: Инструмент усиливает того, кто умеет. В руках незнающего — он усиливает незнание. Ты инструмент держишь — или инструмент держит тебя?"}]},{"n":38,"title":"О том, кто надел чужую шляпу","slug":"038-o-tom-kto-nadel-shuzhuyyu-shlyapu","category":"philosophy","tags":["mentorship","teaching","understanding-vs-memorization","closures"],"source":"Slack-канал монастыря Нандзэн-дзи, 2026 г.","segments":[{"k":"action","t":"Найден в Slack-канале #mentors монастыря Нандзэн-дзи, 2026 г. Сообщение закреплено. Под ним — ноль реакций. Мастер Хидэо поставил единственный эмодзи: 🪵 (бревно). Никто не понял. Мастер не объяснил."},{"k":"action","t":"Ученик вошёл иначе — медленно, с прямой спиной."},{"k":"student","t":"Ученик: «Мастер, у меня теперь трое учеников.»"},{"k":"master","t":"Мастер: «И чему ты учишь?»"},{"k":"student","t":"Ученик: «Замыкания. Промисы. Event Loop.»"},{"k":"master","t":"Мастер: «Покажи, как ты объясняешь замыкание.»"},{"k":"action","t":"Ученик откашлялся."},{"k":"student","t":"Ученик: «Замыкание — это когда функция запоминает переменные из внешнего скоупа даже после того, как внешняя функция завершилась.»"},{"k":"master","t":"Мастер: «MDN.»"},{"k":"student","t":"Ученик: «Что?»"},{"k":"master","t":"Мастер: «Ты процитировал MDN. Слово в слово. Это не понимание. Это — кэш.»"},{"k":"action","t":"Ученик покраснел."},{"k":"master","t":"Мастер: «Когда твой ученик спросит — \"почему замыкание не собирается сборщиком мусора?\" — что ответишь?»"},{"k":"action","t":"Долгое молчание."},{"k":"master","t":"Мастер: «Ты не стал ментором, когда взял учеников. Ты стал ментором, когда смог объяснить то, что когда-то объяснял тебе кто-то другой — своими словами.»"},{"k":"haiku","t":"Шляпа надета. Голова — чужая."},{"k":"question","t":"С чем ты уйдёшь: Ты можешь объяснить каждую вещь, которую преподаёшь, своими словами — без MDN, без конспекта, без паузы?"}]},{"n":39,"title":"О страже, который охраняет пустой храм","slug":"039-o-strazhe-kotoryi-okhranyaet-pustoi-khram","category":"philosophy","tags":["interviews","memorization","understanding","hiring"],"source":"Google Docs, Telegram-каналы, 2026 г.","segments":[{"k":"action","t":"Найден в Google Docs с доступом «только просмотр», ссылка гуляла по Telegram-каналам для подготовки к собесам. Шрифт — Comic Sans. Мастер Хидэо сказал: «Шрифт правильный. Это комедия.»"},{"k":"action","t":"Ученик вернулся после собеседования."},{"k":"student","t":"Ученик: «Мастер, меня спросили: \"Что такое замыкание?\"»"},{"k":"master","t":"Мастер: «И ты ответил?»"},{"k":"student","t":"Ученик: «Я сказал: замыкание — это когда функция помнит место, где родилась. Как монах, покинувший храм, но несущий в себе звук колокола.»"},{"k":"action","t":"Мастер улыбнулся."},{"k":"action","t":"Ученик — нет."},{"k":"student","t":"Ученик: «Мне сказали — неправильно. Сказали: \"Замыкание — это комбинация функции и лексического окружения.\" Точка.»"},{"k":"master","t":"Мастер: «Ты сказал то же самое.»"},{"k":"student","t":"Ученик: «Я знаю. Они — нет.»"},{"k":"master","t":"Мастер: «Кто сидел напротив?»"},{"k":"student","t":"Ученик: «Тимлид. Список вопросов в Notion. Ответы — в соседней вкладке.»"},{"k":"master","t":"Мастер: «Он сверял дословно?»"},{"k":"student","t":"Ученик: «Да.»"},{"k":"action","t":"Мастер закрыл глаза."},{"k":"master","t":"Мастер: «Ты встретил стража. Не хозяина храма. Страж охраняет ворота. Но не знает, что за воротами. Храм пуст. Найди тот храм, где хозяин дома.»"},{"k":"haiku","t":"Страж у ворот. Список слов. Храм — пуст."},{"k":"question","t":"С чем ты уйдёшь: Некоторые собеседования проверяют понимание. Некоторые — память. Ты умеешь отличить одно от другого — и выбрать, куда идти?"}]},{"n":40,"title":"О переводчике, который перевёл себя","slug":"040-o-perevodchike-kotoryi-perevel-sebya","category":"angular","tags":["i18n","overengineering","simplicity","angular","yagni"],"source":"Библиотека храма Тофуку-дзи, 2026 г.","segments":[{"k":"source","t":"Найден в localStorage браузера на публичном компьютере в библиотеке храма Тофуку-дзи, 2026 г. Ключ — i18n_locale. Значение — 'mu'. Ни один fallback не сработал. Приложение показало пустоту. Библиотекарь сказал: «Наконец-то тихо.»"},{"k":"source","t":"Ученик пришёл с идеей."},{"k":"student","t":"Ученик: «Мастер, я хочу сделать переключатель языка.»"},{"k":"master","t":"Мастер: «Делай.»"},{"k":"student","t":"Ученик: «Какую библиотеку взять?»"},{"k":"master","t":"Мастер: «Ты сказал \"хочу сделать\". Не \"хочу спросить\". Сколько языков?»"},{"k":"student","t":"Ученик: «Два. Русский и английский.»"},{"k":"master","t":"Мастер: «Тогда зачем библиотека?»"},{"k":"code","lang":"js","t":"const t = { en: { greeting: 'Hello' }, ru: { greeting: 'Привет' } }\nt[locale].greeting"},{"k":"student","t":"Ученик: «Это же... слишком просто.»"},{"k":"master","t":"Мастер: «Для двух языков и десяти строк — это всё, что нужно. Ты потянулся за большой библиотекой, потому что \"так делают\". Кто делает? Те, у кого сорок локалей. У тебя — два приветствия. Взял молот для гвоздя.»"},{"k":"haiku","t":"Два слова. Один объект. Молоток отложен."},{"k":"question","t":"С чем ты уйдёшь: Решение должно соответствовать задаче. Не амбициям. Не тому, \"как принято\". Ты решаешь задачу — или демонстрируешь знание инструментов?"}]},{"n":41,"title":"О тысяче слуг и одном свитке","slug":"041-o-tysyache-slugh-i-odnom-svitke","category":"angular","tags":["state-management","services","centralized-store","angular","ngrx"],"source":"Сервер храма Касуга-тайся, 2026 г.","segments":[{"k":"action","t":"Извлечён из node_modules заброшенного Angular-проекта, обнаруженного на сервере храма Касуга-тайся, 2026 г. Папка весила 2.3 гигабайта. Внутри node_modules — ещё один node_modules. Мастер Хидэо сказал: «Фрактал страдания.» Запустил ng serve. Ноутбук загорелся. Мастер затушил его книгой «Angular in Action». Она наконец принесла пользу."},{"k":"action","t":"Ученик пришёл с тёмными кругами под глазами."},{"k":"student","t":"Ученик: «Мастер, у меня сорок два сервиса.»"},{"k":"master","t":"Мастер: «Зачем?»"},{"k":"student","t":"Ученик: «Каждый компонент хранит своё состояние. UserService знает пользователя. CartService знает корзину. AuthService знает токен...»"},{"k":"master","t":"Мастер: «Они знают друг о друге?»"},{"k":"student","t":"Ученик: «CartService инжектит AuthService. NotificationService инжектит UserService и CartService. SettingsService инжектит всех.»"},{"k":"master","t":"Мастер: «Нарисуй.»"},{"k":"action","t":"Ученик рисовал десять минут. Стрелки шли во все стороны."},{"k":"master","t":"Мастер: «Они были хорошими слугами. Но ты сделал каждого — маленьким царём. Царство из сорока двух царей — это гражданская война с async pipe.»"},{"k":"student","t":"Ученик: «Тогда нужен стор?»"},{"k":"master","t":"Мастер: «Сорок два рек. Мутят одно озеро. Выкопай колодец.»"},{"k":"student","t":"Ученик: «Централизованный стор — это серебряная пуля?»"},{"k":"master","t":"Мастер: «Нет. Но единый источник правды проще отлаживать, чем сорок два источника мнений. Если ты не можешь ответить \"где прямо сейчас живёт состояние пользователя\" — кто владеет твоим приложением: ты или паутина?»"},{"k":"haiku","t":"Сорок два рек. Одно озеро. Один колодец."},{"k":"question","t":"С чем ты уйдёшь: Сервис в Angular — не стор. Когда сервисов два — это удобство. Когда сорок два — это распределённая система без логов и надежды. Где живёт состояние твоего приложения?"}]}];